<template>
<div class="page-grid ep"><section class="ovg"><article class="oc"><span class="ol">资产总品类数</span><strong class="ov">{{cards.kind}}</strong></article><article class="oc"><span class="ol">总库存数量</span><strong class="ov">{{cards.stock}}</strong></article><article class="oc warn"><span class="ol">低库存品类数</span><strong class="ov">{{cards.low}}</strong></article><article class="oc"><span class="ol">本月领用次数</span><strong class="ov">{{cards.issue}}</strong></article></section><PageCard title="行政/资产管理" description="按企业真实品类台账管理行政耗材与资产。" :hide-header="true" class="page-section panel panel--headerless"><div class="bar topbar-inline"><div class="fs"><el-input v-model="f.k" class="sch" clearable placeholder="搜索资产名称 / 品类编码" /><el-select v-model="f.t" class="sel" clearable placeholder="全部类型"><el-option v-for="i in T" :key="i" :label="i" :value="i" /></el-select><el-select v-model="f.s" class="sel" clearable placeholder="全部状态"><el-option v-for="i in S" :key="i" :label="i" :value="i" /></el-select></div><div class="acts"><el-button type="primary" @click="oc">新增资产</el-button><el-button @click="warnConfig">库存预警设置</el-button></div></div><div class="tb"><el-table :data="paged" :height="tableHeight" width="100%" v-loading="loading" empty-text="暂无资产品类数据"><el-table-column prop="code" label="品类编码" min-width="120" align="center" /><el-table-column prop="name" label="资产名称" min-width="170" align="center" /><el-table-column prop="type" label="资产类型" min-width="110" align="center" /><el-table-column prop="total" label="总数量" min-width="86" align="center" /><el-table-column prop="used" label="已使用数量" min-width="96" align="center" /><el-table-column prop="remain" label="剩余库存" min-width="88" align="center" /><el-table-column label="库存状态" min-width="96" align="center"><template #default="{row}"><el-tag class="tag" :class="sumC(row.stock)" round>{{row.stock}}</el-tag></template></el-table-column><el-table-column label="是否需要采购" min-width="104" align="center"><template #default="{row}"><el-tag class="tag" :class="row.buy?'d':'s'" round>{{row.buy?'需采购':'否'}}</el-tag></template></el-table-column><el-table-column label="操作" min-width="150" fixed="right" align="center"><template #default="{row}"><div class="ag"><el-button link type="primary" @click="od(row)">查看明细</el-button><el-button link type="primary" @click="oe(row)">编辑</el-button></div></template></el-table-column></el-table></div><div class="pg"><el-pagination v-model:current-page="p" :page-size="PS" :total="list.length" layout="slot, prev, pager, next" background><span class="ttl">共计 {{list.length}} 条</span></el-pagination></div></PageCard><el-dialog v-model="show" :title="mode==='c'?'新增资产':'编辑资产品类'" width="680px"><el-form :model="form" label-position="top" class="af"><div class="fg"><el-form-item label="品类编码"><el-input v-model="form.code" /></el-form-item><el-form-item label="资产名称"><el-input v-model="form.name" /></el-form-item><el-form-item label="类型"><el-select v-model="form.type"><el-option v-for="i in T" :key="i" :label="i" :value="i" /></el-select></el-form-item><el-form-item label="总数量"><el-input-number v-model="form.total" :min="1" class="num" /></el-form-item><el-form-item label="安全库存"><el-input-number v-model="form.safe" :min="0" class="num" /></el-form-item><el-form-item label="采购日期"><el-date-picker v-model="form.buyDate" type="date" value-format="YYYY-MM-DD" /></el-form-item><el-form-item label="资产价值"><el-input-number v-model="form.value" :min="0" :step="100" class="num" /></el-form-item></div></el-form><template #footer><el-button @click="show=false">取消</el-button><el-button type="primary" @click="save">保存</el-button></template></el-dialog><el-dialog v-model="dshow" class="asset-detail-dialog" width="1120px" :title="dt"><template #header><div class="dhd"><div class="dhd__title"><span>{{dt}}</span><em v-if="cur">{{cur.code}} · {{cur.type}}</em></div><el-button type="primary" size="small" @click="openDetailCreate">新增明细</el-button></div></template><section class="dsg"><article class="dsc"><span>明细总数</span><strong>{{detailStats.total}}</strong></article><article class="dsc"><span>在用数量</span><strong>{{detailStats.used}}</strong></article><article class="dsc"><span>闲置数量</span><strong>{{detailStats.idle}}</strong></article><article class="dsc warn"><span>待维修数量</span><strong>{{detailStats.repair}}</strong></article></section><div class="bar dbar"><div class="fs"><el-input v-model="df.k" class="sch" clearable placeholder="搜索明细编号 / 领用人 / 部门" /><el-select v-model="df.s" class="sel" clearable placeholder="全部明细状态"><el-option label="闲置" value="闲置" /><el-option label="使用中" value="使用中" /><el-option label="借出中" value="借出中" /><el-option label="待维修" value="待维修" /><el-option label="已报废" value="已报废" /></el-select></div></div><div class="tb asset-detail-dialog__table"><el-table :data="dpaged" :height="360" row-class-name="dRowCls" width="100%" empty-text="暂无匹配的明细数据"><el-table-column prop="no" label="明细编号" min-width="120" align="center" /><el-table-column prop="owner" label="归属领用人" min-width="110" align="center" /><el-table-column prop="dept" label="使用部门" min-width="110" align="center" /><el-table-column label="资产状态" min-width="96" align="center"><template #default="{row}"><el-tag class="tag" :class="detC(row.status)" round>{{row.status}}</el-tag></template></el-table-column><el-table-column prop="receive" label="领用日期" min-width="104" align="center" /><el-table-column prop="back" label="归还日期" min-width="104" align="center" /><el-table-column prop="loc" label="存放位置" min-width="124" align="center" /><el-table-column prop="remark" label="备注" min-width="150" align="center" /><el-table-column label="操作" min-width="260" fixed="right" align="center"><template #default="{row}"><div class="ag ops"><el-button class="abtn abtn-use" size="small" :disabled="row.status==='使用中'" @click="da(row,'u')">领用</el-button><el-button class="abtn abtn-back" size="small" :disabled="!['使用中','借出中'].includes(row.status)" @click="da(row,'b')">归还</el-button><el-button class="abtn abtn-repair" size="small" :disabled="['待维修','已报废'].includes(row.status)" @click="da(row,'m')">维修</el-button><el-button class="abtn abtn-scrap" size="small" :disabled="row.status==='已报废'" @click="da(row,'x')">报废</el-button></div></template></el-table-column></el-table></div><div class="pg"><el-pagination v-model:current-page="dp" :page-size="DP" :total="detailList.length" layout="slot, prev, pager, next" background><span class="ttl">共计 {{detailList.length}} 条，每页 5 条</span></el-pagination></div></el-dialog><el-dialog v-model="detailShow" title="新增资产明细" width="640px"><el-form :model="dform" label-position="top" class="af"><div class="fg"><el-form-item label="明细编号"><el-input v-model="dform.no" placeholder="系统自动生成" /></el-form-item><el-form-item label="归属领用人"><el-input v-model="dform.owner" /></el-form-item><el-form-item label="使用部门"><el-input v-model="dform.dept" /></el-form-item><el-form-item label="资产状态"><el-select v-model="dform.status"><el-option label="闲置" value="闲置" /><el-option label="使用中" value="使用中" /><el-option label="借出中" value="借出中" /><el-option label="待维修" value="待维修" /></el-select></el-form-item><el-form-item label="领用日期"><el-date-picker v-model="dform.receive" type="date" value-format="YYYY-MM-DD" /></el-form-item><el-form-item label="归还日期"><el-date-picker v-model="dform.back" type="date" value-format="YYYY-MM-DD" /></el-form-item><el-form-item label="存放位置"><el-input v-model="dform.loc" /></el-form-item><el-form-item label="备注"><el-input v-model="dform.remark" /></el-form-item></div></el-form><template #footer><el-button @click="detailShow=false">取消</el-button><el-button type="primary" @click="saveDetail">保存</el-button></template></el-dialog></div>
</template>
<script setup>
import {computed,onMounted,reactive,ref,watch} from 'vue';
import {ElMessage,ElMessageBox} from 'element-plus';
import PageCard from '@/components/PageCard.vue';
import {createAsset,getAdministrationSummary} from '@/api/modules';
import { applyApprovedAssetSyncs } from '@/utils/assetApprovalSync';
const PS=10,DP=5,tableHeight='calc(100vh - 320px)',T=['固定资产','会议设备','办公设备','办公耗材','会议资源','印章','车辆','办公家具','行政物料','后勤保障'],S=['充足','低库存','需采购'],U=['使用中','借出中','待维修'];
const loading=ref(false),rows=ref([]),p=ref(1),show=ref(false),mode=ref('c'),eid=ref(''),dshow=ref(false),cur=ref(null),dp=ref(1),detailShow=ref(false),f=reactive({k:'',t:'',s:''}),df=reactive({k:'',s:''}),form=reactive({code:'',name:'',type:'固定资产',total:1,safe:0,buyDate:'',value:0}),dform=reactive({no:'',owner:'',dept:'综合管理部',status:'闲置',receive:'',back:'',loc:'',remark:''});
const O={张琳:['张琳','产品技术部'],韩睿:['韩睿','产品技术部'],刘晨:['刘晨','运营中心'],财务部:['李蓉','财务部'],库存:['行政库房','综合管理部'],'综合管理部':['行政值班','综合管理部'],'行政车队':['行政车队','综合管理部'],唐颖:['唐颖','销售部'],罗嘉:['罗嘉','销售部'],前台:['前台','综合管理部'],茶水间:['后勤值守','综合管理部'],'行政库房':['行政库房','综合管理部']},L={固定资产:'办公区',会议设备:'会议设备柜',办公设备:'办公设备区',办公耗材:'行政仓库',会议资源:'会议区',印章:'行政保险柜',车辆:'地下车库',办公家具:'办公区',行政物料:'前台储物柜',后勤保障:'后勤区'},C={固定资产:3,会议设备:2,办公设备:2,办公耗材:12,会议资源:2,印章:2,车辆:2,办公家具:2,行政物料:10,后勤保障:3};
const code=i=>`CAT-${String(i+1).padStart(4,'0')}`,day=(m,d)=>`2026-${String(m).padStart(2,'0')}-${String(d).padStart(2,'0')}`;
const sumC=s=>s==='充足'?'s':s==='低库存'?'w':'d',detC=s=>s==='使用中'?'p':s==='借出中'?'u':['待维修','已报废'].includes(s)?'d':'g';
function md(x,i){const c=Math.max(Number(x.totalQuantity||C[x.type]||3),1),u=Math.min(['使用中','借出中','待维修'].includes(x.status)?1:0,c),o=O[x.owner]||['行政值班','综合管理部'],a=[];for(let n=0;n<c;n++){const s=n<u?(x.status||'使用中'):'闲置';a.push({id:`${code(i)}-${n+1}`,no:`${code(i)}-D${String(n+1).padStart(3,'0')}`,owner:s==='闲置'?'行政库房':o[0],dept:s==='闲置'?'综合管理部':o[1],status:s,receive:s==='闲置'?'':day((n%4)+1,(n%18)+2),back:'',loc:x.location||L[x.type]||'综合区',remark:s==='待维修'?'待维修处理中':s==='借出中'?'外借登记中':''});}return a;}
function norm(x,i){const ds=(x.details||md(x,i)).map((d,n)=>({...d,id:d.id||`${code(i)}-${n+1}`})),total=Math.max(Number(x.total||x.totalQuantity||ds.length||1),1),safe=Number(x.safe||x.safeStock||Math.max(1,Math.ceil(total*.2))),used=ds.filter(d=>U.includes(d.status)).length,remain=Math.max(total-used,0),stock=remain>safe?'充足':'低库存';return{id:x.id||code(i),code:x.code||x.assetNo||code(i),name:x.name||x.asset||'未命名资产品类',type:x.type||T[0],total,safe,buyDate:x.buyDate||x.purchaseDate||day((i%6)+1,(i%20)+5),value:Number(x.value||0),details:ds,used,remain,stock,buy:stock==='低库存'};}
const list=computed(()=>{const k=f.k.trim().toLowerCase();return rows.value.filter(i=>(!k||i.name.toLowerCase().includes(k)||i.code.toLowerCase().includes(k))&&(!f.t||i.type===f.t)&&(!f.s||(f.s==='需采购'?i.buy:i.stock===f.s)));}),paged=computed(()=>list.value.slice((p.value-1)*PS,p.value*PS)),detail=computed(()=>cur.value?.details||[]),detailList=computed(()=>{const k=df.k.trim().toLowerCase();return detail.value.filter(i=>(!k||String(i.no).toLowerCase().includes(k)||String(i.owner).toLowerCase().includes(k)||String(i.dept).toLowerCase().includes(k))&&(!df.s||i.status===df.s));}),dpaged=computed(()=>detailList.value.slice((dp.value-1)*DP,dp.value*DP)),dt=computed(()=>cur.value?`${cur.value.name} - 资产明细`:'资产明细'),detailStats=computed(()=>({total:detail.value.length,used:detail.value.filter(i=>i.status==='使用中').length,idle:detail.value.filter(i=>i.status==='闲置').length,repair:detail.value.filter(i=>i.status==='待维修').length}));
const cards=computed(()=>({kind:list.value.length,stock:list.value.reduce((a,i)=>a+i.total,0),low:list.value.filter(i=>i.stock==='低库存').length,issue:list.value.flatMap(i=>i.details).filter(i=>String(i.receive).startsWith('2026-04')&&U.includes(i.status)).length}));
watch(list,v=>{const m=Math.max(1,Math.ceil(v.length/PS));if(p.value>m)p.value=m});watch(()=>[f.k,f.t,f.s],()=>p.value=1);watch(detailList,v=>{const m=Math.max(1,Math.ceil(v.length/DP));if(dp.value>m)dp.value=m});watch(()=>[df.k,df.s],()=>dp.value=1);
async function load(){loading.value=true;try{const r=await getAdministrationSummary();rows.value=applyApprovedAssetSyncs(r.data.records||[]).map(norm);p.value=1;}finally{loading.value=false}}
function openCreate(){mode.value='c';eid.value='';Object.assign(form,{code:code(rows.value.length),name:'',type:'固定资产',total:1,safe:0,buyDate:'',value:0});show.value=true}
function openEdit(r){mode.value='e';eid.value=r.id;Object.assign(form,{code:r.code,name:r.name,type:r.type,total:r.total,safe:r.safe,buyDate:r.buyDate,value:r.value});show.value=true}
async function save(){const item=norm({...form,id:eid.value||form.code,details:mode.value==='e'?rows.value.find(i=>i.id===eid.value)?.details:[]},rows.value.length);if(mode.value==='c'){await createAsset(item);rows.value=[item,...rows.value];ElMessage.success('资产品类创建成功')}else{rows.value=rows.value.map(i=>i.id===eid.value?{...item,details:i.details}:i);ElMessage.success('资产品类更新成功')}show.value=false;p.value=1}
function openDetail(r){cur.value=r;dshow.value=true;dp.value=1;df.k='';df.s=''}
function openDetailCreate(){if(!cur.value)return;Object.assign(dform,{no:`${cur.value.code}-D${String(cur.value.details.length+1).padStart(3,'0')}`,owner:'行政库房',dept:'综合管理部',status:'闲置',receive:'',back:'',loc:'',remark:''});detailShow.value=true}
function saveDetail(){if(!cur.value)return;sync(cur.value.id,i=>({...i,total:i.total+1,details:[...i.details,{id:`${i.code}-${i.details.length+1}`,no:dform.no,owner:dform.owner||'行政库房',dept:dform.dept||'综合管理部',status:dform.status,receive:dform.receive,back:dform.back,loc:dform.loc||'综合区',remark:dform.remark||''}]}));detailShow.value=false;ElMessage.success('资产明细新增成功')}
function sync(id,fn){rows.value=rows.value.map((i,n)=>i.id===id?norm(fn(i),n):i);cur.value=rows.value.find(i=>i.id===id)||null}
function detailAct(r,a){if(!cur.value)return;if(a==='x'){ElMessageBox.confirm(`确认将 ${r.no} 执行报废吗？报废后将扣减当前品类总数量。`,'报废确认',{type:'warning'}).then(()=>runDetailAct(r,a)).catch(()=>{});return}runDetailAct(r,a)}
function runDetailAct(r,a){sync(cur.value.id,i=>{const ds=i.details.map(d=>{if(d.id!==r.id)return d;if(a==='u')return {...d,status:'使用中',owner:d.owner==='行政库房'?'待分配':d.owner,receive:d.receive||day(4,13),back:'',remark:'已领用'};if(a==='b')return {...d,status:'闲置',owner:'行政库房',dept:'综合管理部',back:day(4,13),remark:'剩余库存'};if(a==='m')return {...d,status:'待维修',remark:'待维修处理中'};return {...d,status:'已报废',remark:'已完成报废'};});return {...i,total:a==='x'&&i.total>0?i.total-1:i.total,details:ds};});ElMessage.success(a==='u'?'领用成功':a==='b'?'归还成功':a==='m'?'已转入维修':'已完成报废')}
function warnConfig(){ElMessage.info('库存预警当前按安全库存自动计算，可继续扩展独立预警配置。')}
const rowCls=({row})=>row.buy?'sum-row-danger':row.stock==='低库存'?'sum-row-warning':'',dRowCls=({row})=>['待维修','已报废'].includes(row.status)?'detail-row-danger':row.status==='借出中'?'detail-row-purple':'',oc=openCreate,oe=openEdit,od=openDetail,da=detailAct;onMounted(load);
</script>
